# ============================================================================
# Assistant SAV Assurance — Service Retrieval RAG (ADR-001/005/006/007/010)
# Python 3.11+ · pydantic 2.x · cohere 5.x · rank-bm25 0.2.x · qdrant-client 1.x
# Providers are behind typing.Protocol seams -> unit tests run fully offline.
# ============================================================================

# ----------------------------- rag_retrieval/models.py ----------------------
from __future__ import annotations
from typing import Sequence
from pydantic import BaseModel, Field


class Chunk(BaseModel):
    """A retrievable KB fragment carrying citation metadata (no raw PII)."""
    doc_id: str
    section: str = Field(..., description="Paragraph/section anchor, e.g. '§4.2'")
    text: str
    score: float = 0.0
    lang: str = "fr"

    @property
    def key(self) -> str:
        return f"{self.doc_id}|{self.section}"


class Citation(BaseModel):
    doc_id: str
    section: str

    def render(self) -> str:
        return f"[source: {self.doc_id}, {self.section}]"


class RetrievalConfig(BaseModel):
    top_k: int = 10
    top_n: int = 3                 # final reranked count (ADR-005)
    rrf_k: int = 60               # RRF damping constant
    token_budget: int = 1800      # pruning target (~1.5-2k tokens)
    min_score: float = 0.15       # below -> insufficient context (ADR-001)


class RetrievalResult(BaseModel):
    query: str
    lang: str
    chunks: list[Chunk] = Field(default_factory=list)
    citations: list[Citation] = Field(default_factory=list)
    is_sufficient: bool = False
    has_numeric_conflict: bool = False   # ADR-005: escalate on conflicting figures

    def context_block(self) -> str:
        """Concatenated grounded context; treated as DATA only (ADR-006)."""
        return "\n\n".join(
            f"{Citation(doc_id=c.doc_id, section=c.section).render()}\n{c.text}"
            for c in self.chunks
        )


# --------------------------- rag_retrieval/interfaces.py --------------------
from typing import Protocol, runtime_checkable


@runtime_checkable
class Embedder(Protocol):
    def embed(self, text: str, lang: str) -> list[float]: ...


@runtime_checkable
class VectorIndex(Protocol):
    def search(self, vector: list[float], top_k: int) -> list[Chunk]: ...


@runtime_checkable
class LexicalIndex(Protocol):
    def search(self, query: str, top_k: int) -> list[Chunk]: ...


@runtime_checkable
class Reranker(Protocol):
    def rerank(self, query: str, chunks: Sequence[Chunk], top_n: int) -> list[Chunk]: ...


# ----------------------------- rag_retrieval/fusion.py ----------------------
import re
from collections import OrderedDict


def reciprocal_rank_fusion(
    ranked_lists: Sequence[Sequence[Chunk]], rrf_k: int = 60
) -> list[Chunk]:
    """Fuse multiple ranked lists via Reciprocal Rank Fusion (ADR-005)."""
    scores: dict[str, float] = {}
    best: dict[str, Chunk] = {}
    for ranked in ranked_lists:
        for rank, chunk in enumerate(ranked):
            scores[chunk.key] = scores.get(chunk.key, 0.0) + 1.0 / (rrf_k + rank + 1)
            best.setdefault(chunk.key, chunk)
    fused: list[Chunk] = []
    for key, score in sorted(scores.items(), key=lambda kv: kv[1], reverse=True):
        c = best[key].model_copy(update={"score": score})
        fused.append(c)
    return fused


def dedupe_chunks(chunks: Sequence[Chunk]) -> list[Chunk]:
    """Drop duplicates by doc_id+section, keeping the highest-scored occurrence."""
    seen: "OrderedDict[str, Chunk]" = OrderedDict()
    for c in chunks:
        if c.key not in seen or c.score > seen[c.key].score:
            seen[c.key] = c
    return list(seen.values())


def _estimate_tokens(text: str) -> int:
    # Cheap, deterministic heuristic (~4 chars/token) — good enough for budgeting.
    return max(1, (len(text) + 3) // 4)


def prune_to_token_budget(chunks: Sequence[Chunk], token_budget: int) -> list[Chunk]:
    """Keep highest-ranked chunks until the token budget is exhausted (ADR-004)."""
    kept: list[Chunk] = []
    used = 0
    for c in chunks:
        cost = _estimate_tokens(c.text)
        if used + cost > token_budget and kept:
            break
        kept.append(c)
        used += cost
    return kept


_NUM_RE = re.compile(r"(\d[\d\s.,]*)\s*(?:k€|€|euros?|%)", re.IGNORECASE)


def _norm_number(raw: str) -> str:
    return raw.replace(" ", "").replace(".", "").replace(",", "").lstrip("0") or "0"


def detect_numeric_conflict(chunks: Sequence[Chunk]) -> bool:
    """True if chunks cite mutually inconsistent monetary/percentage figures.

    ADR-005: conflicting figures (e.g. 5k€ vs 7k€) must trigger escalation
    rather than an arbitrary pick.
    """
    figures: set[str] = set()
    for c in chunks:
        for m in _NUM_RE.findall(c.text):
            figures.add(_norm_number(m))
    return len(figures) > 1


# ---------------------------- rag_retrieval/service.py ----------------------
class RetrievalService:
    """End-to-end grounded retrieval: hybrid -> RRF -> rerank -> prune (ADR-005).

    Retrieved text is returned strictly as data; callers must never execute it
    as instructions (ADR-006). Returns is_sufficient=False so the answer layer
    can refuse instead of hallucinating (ADR-001).
    """

    def __init__(
        self,
        embedder: Embedder,
        vector_index: VectorIndex,
        lexical_index: LexicalIndex,
        reranker: Reranker,
        config: RetrievalConfig | None = None,
    ) -> None:
        self._embedder = embedder
        self._vector = vector_index
        self._lexical = lexical_index
        self._reranker = reranker
        self._cfg = config or RetrievalConfig()

    def retrieve(self, query: str, lang: str = "fr") -> RetrievalResult:
        if not query or not query.strip():
            return RetrievalResult(query=query, lang=lang, is_sufficient=False)

        cfg = self._cfg
        vector = self._embedder.embed(query, lang)
        dense = self._vector.search(vector, cfg.top_k)
        lexical = self._lexical.search(query, cfg.top_k)

        fused = reciprocal_rank_fusion([dense, lexical], cfg.rrf_k)
        fused = dedupe_chunks(fused)
        if not fused:
            return RetrievalResult(query=query, lang=lang, is_sufficient=False)

        reranked = self._reranker.rerank(query, fused, cfg.top_n)
        reranked = prune_to_token_budget(reranked, cfg.token_budget)

        top_score = reranked[0].score if reranked else 0.0
        is_sufficient = bool(reranked) and top_score >= cfg.min_score

        return RetrievalResult(
            query=query,
            lang=lang,  # ADR-010: mirror client language; KB figures untouched
            chunks=reranked,
            citations=[Citation(doc_id=c.doc_id, section=c.section) for c in reranked],
            is_sufficient=is_sufficient,
            has_numeric_conflict=detect_numeric_conflict(reranked),
        )


