import pytest
from rag_retrieval.models import Chunk, RetrievalConfig
from rag_retrieval.service import RetrievalService


class FakeEmbedder:
    def embed(self, text: str, lang: str) -> list[float]:
        return [float(len(text)), float(len(lang))]


class FakeIndex:
    def __init__(self, chunks): self._chunks = chunks
    def search(self, *_args, **_kwargs): return list(self._chunks)


class FakeReranker:
    def rerank(self, query, chunks, top_n):
        ranked = sorted(chunks, key=lambda c: c.score, reverse=True)[:top_n]
        # assign descending normalized scores so thresholds are testable
        return [c.model_copy(update={"score": 0.9 - 0.1 * i})
                for i, c in enumerate(ranked)]


@pytest.fixture
def chunks():
    return [
        Chunk(doc_id="POL-12", section="§4.2", text="Le plafond est de 5k€."),
        Chunk(doc_id="POL-12", section="§4.3", text="Délai de carence 30 jours."),
        Chunk(doc_id="POL-99", section="§1.1", text="Conditions générales 2026."),
    ]


@pytest.fixture
def service(chunks):
    return RetrievalService(
        embedder=FakeEmbedder(),
        vector_index=FakeIndex(chunks),
        lexical_index=FakeIndex(chunks),
        reranker=FakeReranker(),
        config=RetrievalConfig(token_budget=1800, min_score=0.15),
    )


