# tests/test_fusion.py
# ============================================================================
from rag_retrieval.models import Chunk
from rag_retrieval.fusion import (
    reciprocal_rank_fusion, dedupe_chunks, prune_to_token_budget,
    detect_numeric_conflict, _estimate_tokens,
)


def _c(doc, sec, text="x", score=0.0):
    return Chunk(doc_id=doc, section=sec, text=text, score=score)


def test_rrf_orders_by_consensus():
    a = [_c("A", "1"), _c("B", "1"), _c("C", "1")]
    b = [_c("B", "1"), _c("A", "1"), _c("D", "1")]
    fused = reciprocal_rank_fusion([a, b])
    assert {fused[0].key, fused[1].key} == {"A|1", "B|1"}
    assert fused[0].score >= fused[1].score


def test_rrf_empty_input():
    assert reciprocal_rank_fusion([]) == []


def test_dedupe_keeps_highest_score():
    out = dedupe_chunks([_c("A", "1", score=0.2), _c("A", "1", score=0.9)])
    assert len(out) == 1 and out[0].score == 0.9


def test_prune_respects_budget():
    big = [_c("A", "1", text="w" * 4000), _c("B", "1", text="w" * 4000)]
    pruned = prune_to_token_budget(big, token_budget=1800)
    assert len(pruned) == 1


def test_prune_always_keeps_at_least_one():
    assert len(prune_to_token_budget([_c("A", "1", text="w" * 9999)], 10)) == 1


def test_estimate_tokens_monotonic():
    assert _estimate_tokens("a" * 8) > _estimate_tokens("a")


def test_numeric_conflict_detected():
    assert detect_numeric_conflict(
        [_c("A", "1", "plafond 5k€"), _c("B", "1", "plafond 7k€")]) is True


def test_numeric_conflict_absent_when_consistent():
    assert detect_numeric_conflict(
        [_c("A", "1", "plafond 5k€"), _c("B", "1", "encore 5k€")]) is False


