import pytest
from rag_retrieval.models import Chunk, RetrievalConfig
from rag_retrieval.service import RetrievalService
from tests.conftest import FakeEmbedder, FakeIndex, FakeReranker


def test_nominal_returns_top_n_with_citations(service):
    res = service.retrieve("plafond garantie", lang="fr")
    assert res.is_sufficient is True
    assert len(res.chunks) <= 3 and res.chunks
    assert res.citations[0].render().startswith("[source: ")
    assert "[source:" in res.context_block()


def test_empty_query_is_insufficient(service):
    assert service.retrieve("   ").is_sufficient is False


def test_empty_retrieval_refuses():
    svc = RetrievalService(FakeEmbedder(), FakeIndex([]), FakeIndex([]), FakeReranker())
    res = svc.retrieve("anything")
    assert res.is_sufficient is False and res.chunks == []


def test_low_score_is_insufficient(chunks):
    svc = RetrievalService(
        FakeEmbedder(), FakeIndex(chunks), FakeIndex(chunks), FakeReranker(),
        config=RetrievalConfig(min_score=0.99),  # threshold above any score
    )
    assert svc.retrieve("plafond").is_sufficient is False


def test_language_is_mirrored(service):
    assert service.retrieve("coverage limit", lang="en").lang == "en"


def test_numeric_conflict_flagged():
    conflicting = [
        Chunk(doc_id="A", section="§1", text="plafond 5k€"),
        Chunk(doc_id="B", section="§2", text="plafond 7k€"),
    ]
    svc = RetrievalService(
        FakeEmbedder(), FakeIndex(conflicting), FakeIndex(conflicting), FakeReranker())
    assert svc.retrieve("plafond").has_numeric_conflict is True

