# infra/main.tf — Terraform (AWS eu-west-3 / Paris) — residence donnees UE (RGPD).
# Compute: EKS + Karpenter (node groups Spot pour FinOps). Vector DB: RDS PostgreSQL + pgvector.
# Secrets (cle Cohere Rerank, creds DB) dans Secrets Manager, jamais en payload (ADR-007).
# terraform >= 1.7, provider aws ~> 5.x. Backend distant S3 + verrou DynamoDB.

terraform {
  required_version = ">= 1.7"
  required_providers {
    aws = { source = "hashicorp/aws", version = "~> 5.60" }
  }
  backend "s3" {
    bucket         = "rag-tfstate-eu-west-3"
    key            = "rag-retrieval/terraform.tfstate"
    region         = "eu-west-3"
    dynamodb_table = "rag-tflock"
    encrypt        = true
  }
}

provider "aws" {
  region = "eu-west-3" # Paris — residence UE imposee
  default_tags {
    tags = {
      project     = "rag-retrieval-sav"
      environment = var.environment
      cost-center = "sav-assurance"   # tag FinOps
      managed-by  = "terraform"
      data-residency = "eu"
    }
  }
}

variable "environment" { type = string, default = "staging" }
variable "vpc_cidr"    { type = string, default = "10.40.0.0/16" }

# --- Reseau ---
module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "~> 5.8"
  name    = "rag-${var.environment}"
  cidr    = var.vpc_cidr
  azs             = ["eu-west-3a", "eu-west-3b", "eu-west-3c"]
  private_subnets = ["10.40.1.0/24", "10.40.2.0/24", "10.40.3.0/24"]
  public_subnets  = ["10.40.101.0/24", "10.40.102.0/24", "10.40.103.0/24"]
  enable_nat_gateway = true
  single_nat_gateway = var.environment != "prod" # FinOps: 1 NAT hors prod
}

# --- EKS + Karpenter (Spot) ---
module "eks" {
  source  = "terraform-aws-modules/eks/aws"
  version = "~> 20.0"
  cluster_name    = "rag-${var.environment}"
  cluster_version = "1.30"
  vpc_id     = module.vpc.vpc_id
  subnet_ids = module.vpc.private_subnets
  enable_irsa = true # OIDC pour IRSA (pods -> Secrets Manager sans cle statique)
  eks_managed_node_groups = {
    spot = {
      capacity_type  = "SPOT"        # FinOps: ~ -70% vs on-demand
      instance_types = ["m6i.large", "m6a.large", "m5.large"]
      min_size = 2, max_size = 8, desired_size = 2
    }
  }
}

# --- ECR (scan on push, immutable) ---
resource "aws_ecr_repository" "rag" {
  name                 = "rag-retrieval"
  image_tag_mutability = "IMMUTABLE"
  image_scanning_configuration { scan_on_push = true }
  encryption_configuration { encryption_type = "KMS" }
}

# --- Vector DB : RDS PostgreSQL + pgvector (residence UE, chiffre KMS) ---
resource "aws_db_instance" "vector" {
  identifier              = "rag-pgvector-${var.environment}"
  engine                  = "postgres"
  engine_version          = "16.3"
  instance_class          = var.environment == "prod" ? "db.r6g.large" : "db.t4g.medium"
  allocated_storage       = 50
  storage_encrypted       = true
  multi_az                = var.environment == "prod"
  db_subnet_group_name    = aws_db_subnet_group.vector.name
  vpc_security_group_ids  = [aws_security_group.db.id]
  backup_retention_period = 7
  deletion_protection     = var.environment == "prod"
  skip_final_snapshot     = var.environment != "prod"
  # pgvector active via parameter group / migration applicative
}

resource "aws_db_subnet_group" "vector" {
  name       = "rag-db-${var.environment}"
  subnet_ids = module.vpc.private_subnets
}

resource "aws_security_group" "db" {
  name_prefix = "rag-db-"
  vpc_id      = module.vpc.vpc_id
  ingress { from_port = 5432, to_port = 5432, protocol = "tcp", cidr_blocks = [var.vpc_cidr] }
  egress  { from_port = 0, to_port = 0, protocol = "-1", cidr_blocks = ["0.0.0.0/0"] }
}

# --- Secrets (cle Cohere Rerank, creds DB) — jamais en clair dans le code/payload ---
resource "aws_secretsmanager_secret" "cohere" {
  name                    = "rag/cohere-api-key"
  recovery_window_in_days = 7
}
resource "aws_secretsmanager_secret" "db" {
  name = "rag/db-credentials"
}

# --- Observabilite ---
resource "aws_cloudwatch_log_group" "rag" {
  name              = "/eks/rag-${var.environment}"
  retention_in_days = 30
}

output "cluster_name" { value = module.eks.cluster_name }
output "ecr_url"       { value = aws_ecr_repository.rag.repository_url }
output "db_endpoint"   { value = aws_db_instance.vector.address, sensitive = true }

